html:
{% set attendees = frappe.get_all(
	'Event Attendee',
	fields = ['name1', 'company_name', 'category', 'qr'],
	order_by = 'name1 asc',
	page_length = 5000
) %}

<style>
	@page {
		size: 13in 19in;
		margin: 0.20in;
	}

	html, body {
		margin: 0;
		padding: 0;
		font-family: Arial, Helvetica, sans-serif;
		color: #111;
		font-size: 10pt;
	}

	.sheet {
		width: 100%;
	}

.badge-grid {
	display: grid;
	grid-template-columns: repeat(3, 4.1in);
	grid-auto-rows: 3in;
	gap: 0.10in;
	justify-content: start;
	align-content: start;
}

.badge {
	width: 4.1in;
	height: 3in;
	box-sizing: border-box;
	border: 1px solid #cfcfcf;
	padding: 0.08in;
	display: flex;
	flex-direction: row;
	align-items: stretch;
	page-break-inside: avoid;
	break-inside: avoid;
	overflow: hidden;
	background: #fff;
}
	.left {
		width: 45%;
		padding-right: 0.08in;

		display: flex;
		flex-direction: column;
		align-items: stretch;
		justify-content: flex-start;
	}

	.qr-box {
		width: 100%;
		height: 1.30in;
		border: 1px solid #ddd;
		display: flex;
		align-items: center;
		justify-content: center;
		background: #fff;
		overflow: hidden;
		margin-bottom: 6px;
	}

	.qr-box img {
		width: 90%;
		height: 90%;
		object-fit: contain;
		display: block;
	}

	.no-qr {
		font-size: 8pt;
		color: #777;
		text-align: center;
		line-height: 1.2;
		padding: 4px;
	}

.right {
	width: 64%;
	display: flex;
	flex-direction: column;
	justify-content: flex-start;
	gap: 10px;
	min-width: 0;
	text-align: left;
	height: 100%;
}

.company-block {
	min-height: 30px; /* optional: keeps company area visually stable */
}

.swot-block {
	margin-top: 40px; /* pushes SWOT section to bottom */
}

.swot-title {
	margin-top: 8px;
	font-size: 17px;
	font-weight: 700;
	line-height: 1.2;
}

.write-box.swot {
	min-height:50px;
}
.block {
	display: flex;
	flex-direction: column;
	gap: 4px;
	margin-bottom: 4px;
	min-width: 0; /* also helps children wrap */
}

.company-name {
	font-size: 17px;
	font-weight: 700;
	line-height: 1.2;
	white-space: normal;
	overflow-wrap: break-word;
	word-break: break-word;
	min-width: 0;
	max-width: 100%;
}
	.value {
		font-size: 10px;
		font-weight: 400;
		line-height: 1.5;
		word-break: break-word;
		overflow-wrap: break-word;
	}

	.value.name {
		font-size: 10px;
		font-weight: 400;
	}

	.manual-label {
		font-size: 17px;
		font-weight: 700;
		line-height: 1.2;
		margin-bottom: 2px;
	}

	.write-box {
		width: 70%;
		min-height: 18px;
		border: 1px solid #bfbfbf;
		box-sizing: border-box;
		padding: 2px 4px;
		font-size: 10px;
		line-height: 1.2;
		background: #fff;
	}
	.byob{
		width: 100%;
		min-height: 28px;
		border: 1px solid #bfbfbf;
		box-sizing: border-box;
		padding: 2px 4px;
		font-size: 10px;
		line-height: 1.2;
		background: #fff;
	}

	.write-box.swot {
		min-height: 28px;
	}

	.empty-state {
		padding: 24px;
		font-size: 12pt;
		color: #444;
	}
</style>

<div class="sheet">
	{% if attendees and attendees|length > 0 %}
		<div class="badge-grid">
			{% for row in attendees %}
				<div class="badge">
					<div class="left">
						<div>
							{% if row.qr %}
								<img src="{{ row.qr }}" alt="{{ row.name1 }}">
							{% else %}
								<div class="no-qr">No QR</div>
							{% endif %}
						</div>

						<div class="block">
							<div class="manual-label"><b>BYOB Detail</b></div>
							<div class="write-box byob">&nbsp;</div>
						</div>
						<div class="block">
							<div style="margin-top:9px;">Table No: 1</div>

						</div>
					</div>

                    <div class="right">
                    	<div class="block">
                    		<div class="manual-label" style="margin-top:20px;">{{ row.name1 }}</div>
                    	</div>

                    	<div class="block company-block">
                    		<div class="manual-label company-name">{{ row.company_name  }}</div>
                    	</div>

                    	<div class="block swot-block">
                    		<div class="swot-title">Put your SWOT</div>
                    		<div class="write-box swot">&nbsp;</div>
                    	</div>

                    	<div>
                    		<div>Table No: 28</div>
                    	</div>
                    </div>
				</div>
			{% endfor %}
		</div>
	{% else %}
		<div class="empty-state">No Event Attendee records found.</div>
	{% endif %}
</div>
